+  /* tslint:disable */
+  const { toStream } = require('web-stream-tools').default;
+
+  class Counter extends Readable {
+    private _index: number;
+    private _max: number;
+
+    constructor(options?: ReadableOptions) {
+      super(options);
+      this._max = 3;
+      this._index = 0;
+    }
+
+    _read() {
+      this.push(++this._index > this._max ? null : `${this._index}`);
+    }
+  }
