+): AsyncIterableX<[T, T2, T3, T4, T5]>;
+export function combineLatest<T, T2, T3, T4, T5, T6>(
+  source: AsyncIterable<T>,
+  source2: AsyncIterable<T2>,
+  source3: AsyncIterable<T3>,
