+export function combineLatest<T, T2, T3, T4, T5, R>(
+  project: (values: [T, T2, T3, T4, T5]) => R | Promise<R>,
+  source: AsyncIterable<T>,
+  source2: AsyncIterable<T2>,
+  source3: AsyncIterable<T3>,
+  source4: AsyncIterable<T4>,
