+  await hasNext(t, it, 1);
+  await hasNext(t, it, 2);
+  await hasNext(t, it, 3);
+  await hasNext(t, it, 4);
+  await noNext(t, it);
+  t.end();
+});
+
+test('AsyncIterable#skipWhile skips all', async t => {
+  const xs = of(1, 2, 3, 4);
+  const ys = skipWhile(xs, async () => true);
+
